import { Component, h, Prop } from '@stencil/core';
import { RenderCardContent } from '../../utils/card-content-renderer';
import { HeadingLevel } from '../../models/card.model';

@Component({
  tag: 'wdpr-card-xlarge-content',
  shadow: true,
})
export class WdprCardXlargeContent {
  @Prop() disabled: boolean = false;
  @Prop() headlineLabel: string;
  @Prop() headingLevel: HeadingLevel = 'h1';
  @Prop() headlineSubtext: string;
  @Prop() hasGradient: boolean = false;
  @Prop() isMobile: boolean = false;
  @Prop() primaryHeadline: string;
  @Prop() tagLabel: string;
  @Prop() topPadding: boolean = false;
  @Prop() headlineSize: 'xsmall' | 'small' | 'medium' | 'large' | 'xlarge' = 'xlarge';
  @Prop() subHeadlineSize: 'small' | 'large' = 'large';
  @Prop() tagSize: 'small' | 'large' = 'large';

  render() {
    const props = {
      primaryHeadline: this.primaryHeadline,
      headlineLabel: this.headlineLabel,
      headlineSubtext: this.headlineSubtext,
      headingLevel: this.headingLevel,
      hasGradient: this.hasGradient,
      isMobile: this.isMobile,
      tagLabel: this.tagLabel,
      topPadding: this.topPadding,
      headlineSize: this.headlineSize,
      subHeadlineSize: this.subHeadlineSize,
      tagSize: this.tagSize,
    };

    return (
      <RenderCardContent disabled={this.disabled} variant='xlarge' {...props} />
    );
  }
}
